'use client';

import { useEffect, useState } from 'react';
import { MOCK_EXCHANGE_RATE } from '@/data/mockData';
import { formatCurrency } from '@/lib/formatters';

export interface AmountData {
  senderAmount: number;
  narration:    string;
}

interface AmountStepProps {
  data:         AmountData;
  onChange:     (data: AmountData) => void;
  errors:       Partial<Record<keyof AmountData, string>>;
  onClearError: (field: keyof AmountData) => void;
}

export function AmountStep({ data, onChange, errors, onClearError }: AmountStepProps) {
  const [rawAmount, setRawAmount] = useState(
    data.senderAmount > 0 ? data.senderAmount.toString() : ''
  );

  const rate           = MOCK_EXCHANGE_RATE.rate;
  const receiverAmount = data.senderAmount > 0 ? data.senderAmount / rate : 0;
  const fee            = data.senderAmount > 0 ? Math.round(data.senderAmount * 0.005) : 0;
  const totalDebit     = data.senderAmount + fee;

  useEffect(() => {
    const parsed = parseFloat(rawAmount.replace(/,/g, ''));
    onChange({
      ...data,
      senderAmount: isNaN(parsed) ? 0 : parsed,
    });
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [rawAmount]);

  return (
    <div className="flex flex-col gap-5">
      <div>
        <h2 className="text-base font-semibold text-zinc-100">Amount to send</h2>
        <p className="mt-1 text-sm text-zinc-600">How much Naira are you sending?</p>
      </div>

      {/* Amount input */}
      <div className="flex flex-col gap-1.5">
        <label htmlFor="amount" className="text-[11px] font-semibold uppercase tracking-widest text-zinc-500">
          You send (NGN)
        </label>
        <div className="relative">
          <span className="absolute left-4 top-1/2 -translate-y-1/2 font-mono text-sm text-zinc-500">₦</span>
          <input
            id="amount"
            type="number"
            placeholder="0"
            value={rawAmount}
            min={0}
            onChange={(e) => {
              setRawAmount(e.target.value);
              onClearError('senderAmount');
            }}
            className={[
              'w-full rounded-xl border bg-[#0c0c1a] pl-8 pr-4 py-3 font-mono text-sm text-zinc-100 placeholder:text-zinc-700',
              'outline-none transition-all duration-150 focus:ring-1',
              errors.senderAmount
                ? 'border-red-500/50 focus:border-red-500 focus:ring-red-500/20'
                : 'border-[#1e1e32] focus:border-indigo-500/50 focus:ring-indigo-500/20',
            ].join(' ')}
          />
        </div>
        {errors.senderAmount && (
          <p className="text-[11px] text-red-400">{errors.senderAmount}</p>
        )}
      </div>

      {/* Quick amount buttons */}
      <div className="flex gap-2 flex-wrap">
        {[10_000, 50_000, 100_000, 250_000].map((amount) => (
          <button
            key={amount}
            type="button"
            onClick={() => {
              setRawAmount(amount.toString());
              onClearError('senderAmount');
            }}
            className={[
              'rounded-lg border px-3 py-1.5 text-[11.5px] font-medium transition-all duration-150',
              data.senderAmount === amount
                ? 'border-indigo-500/40 bg-indigo-600/20 text-indigo-400'
                : 'border-[#1e1e32] bg-[#0c0c1a] text-zinc-500 hover:border-[#2a2a45] hover:text-zinc-400',
            ].join(' ')}
          >
            ₦{(amount / 1000).toFixed(0)}K
          </button>
        ))}
      </div>

      {/* Exchange breakdown */}
      {data.senderAmount > 0 && (
        <div className="rounded-xl border border-[#1e1e32] bg-[#0c0c1a] p-4 flex flex-col gap-3">
          <div className="flex items-center justify-between text-[12.5px]">
            <span className="text-zinc-600">Recipient gets</span>
            <span className="font-mono font-semibold text-emerald-400">
              {formatCurrency(receiverAmount, 'GHS')}
            </span>
          </div>
          <div className="flex items-center justify-between text-[12.5px]">
            <span className="text-zinc-600">Exchange rate</span>
            <span className="font-mono text-zinc-400">1 GHS = ₦{rate.toFixed(2)}</span>
          </div>
          <div className="flex items-center justify-between text-[12.5px]">
            <span className="text-zinc-600">Transfer fee (0.5%)</span>
            <span className="font-mono text-zinc-400">{formatCurrency(fee, 'NGN')}</span>
          </div>
          <div className="border-t border-[#1e1e32] pt-3 flex items-center justify-between text-[12.5px]">
            <span className="text-zinc-400 font-medium">Total debit</span>
            <span className="font-mono font-semibold text-zinc-200">{formatCurrency(totalDebit, 'NGN')}</span>
          </div>
        </div>
      )}

      {/* Narration */}
      <div className="flex flex-col gap-1.5">
        <label htmlFor="narration" className="text-[11px] font-semibold uppercase tracking-widest text-zinc-500">
          Narration <span className="normal-case text-zinc-700">(optional)</span>
        </label>
        <input
          id="narration"
          type="text"
          placeholder="e.g. School fees, Monthly support"
          maxLength={100}
          value={data.narration}
          onChange={(e) => onChange({ ...data, narration: e.target.value })}
          className="w-full rounded-xl border border-[#1e1e32] bg-[#0c0c1a] px-4 py-3 text-sm text-zinc-100 placeholder:text-zinc-700 outline-none focus:border-indigo-500/50 focus:ring-1 focus:ring-indigo-500/20 transition-all"
        />
      </div>
    </div>
  );
}
