'use client';

import { formatCurrency } from '@/lib/formatters';
import { MOCK_EXCHANGE_RATE } from '@/data/mockData';
import type { RecipientData } from './RecipientStep';
import type { AmountData } from './AmountStep';

interface ReviewStepProps {
  recipient: RecipientData;
  amount:    AmountData;
}

export function ReviewStep({ recipient, amount }: ReviewStepProps) {
  const rate           = MOCK_EXCHANGE_RATE.rate;
  const receiverAmount = amount.senderAmount / rate;
  const fee            = Math.round(amount.senderAmount * 0.005);
  const totalDebit     = amount.senderAmount + fee;

  const rows = [
    { label: 'Recipient',       value: recipient.recipientName },
    { label: 'Bank / Wallet',   value: recipient.recipientBank },
    { label: 'Account number',  value: recipient.recipientAccount },
    { label: 'You send',        value: formatCurrency(amount.senderAmount, 'NGN'), mono: true },
    { label: 'Recipient gets',  value: formatCurrency(receiverAmount, 'GHS'),       mono: true, accent: true },
    { label: 'Exchange rate',   value: `1 GHS = ₦${rate.toFixed(2)}`,              mono: true },
    { label: 'Fee',             value: formatCurrency(fee, 'NGN'),                  mono: true },
    { label: 'Total debit',     value: formatCurrency(totalDebit, 'NGN'),           mono: true, bold: true },
  ];

  if (amount.narration) {
    rows.splice(3, 0, { label: 'Narration', value: amount.narration });
  }

  return (
    <div className="flex flex-col gap-5">
      <div>
        <h2 className="text-base font-semibold text-zinc-100">Review transfer</h2>
        <p className="mt-1 text-sm text-zinc-600">Confirm the details before sending.</p>
      </div>

      <div className="rounded-xl border border-[#1e1e32] bg-[#0c0c1a] overflow-hidden">
        {rows.map((row, i) => (
          <div
            key={row.label}
            className={[
              'flex items-center justify-between px-4 py-3 text-[13px]',
              i < rows.length - 1 ? 'border-b border-[#1a1a2e]' : '',
              row.bold ? 'bg-[#0f0f1a]' : '',
            ].join(' ')}
          >
            <span className="text-zinc-600">{row.label}</span>
            <span className={[
              row.mono ? 'font-mono' : '',
              row.accent ? 'text-emerald-400 font-semibold' : '',
              row.bold ? 'text-zinc-100 font-semibold' : 'text-zinc-300',
            ].join(' ')}>
              {row.value}
            </span>
          </div>
        ))}
      </div>

      <div className="flex items-start gap-3 rounded-xl border border-amber-500/20 bg-amber-500/5 px-4 py-3">
        <svg className="mt-0.5 flex-shrink-0 text-amber-400" width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
          <path d="M10.29 3.86L1.82 18a2 2 0 0 0 1.71 3h16.94a2 2 0 0 0 1.71-3L13.71 3.86a2 2 0 0 0-3.42 0z"/>
          <line x1="12" y1="9" x2="12" y2="13"/>
          <line x1="12" y1="17" x2="12.01" y2="17"/>
        </svg>
        <p className="text-[11.5px] text-amber-400/80 leading-relaxed">
          Transfers are processed via USDC on Base L2. Funds typically arrive within 2–5 minutes.
        </p>
      </div>
    </div>
  );
}
